    <script>
        let hoverTimeout;
        let leaveTimeout;

        // Desktop mega menu hover functionality
        document.addEventListener('DOMContentLoaded', function() {
            const navItems = document.querySelectorAll('.nav-item');

            navItems.forEach(item => {
                const megaMenu = item.querySelector('.mega-menu');
                if (!megaMenu) return;

                item.addEventListener('mouseenter', () => {
                    clearTimeout(leaveTimeout);
                    hoverTimeout = setTimeout(() => {
                        megaMenu.style.opacity = '1';
                        megaMenu.style.visibility = 'visible';
                        megaMenu.style.transform = 'translateX(-50%) translateY(0)';
                    }, 150);
                });

                item.addEventListener('mouseleave', () => {
                    clearTimeout(hoverTimeout);
                    leaveTimeout = setTimeout(() => {
                        megaMenu.style.opacity = '0';
                        megaMenu.style.visibility = 'hidden';
                        megaMenu.style.transform = 'translateX(-50%) translateY(-10px)';
                    }, 300);
                });
            });
        });

        // Mobile navigation functions
        function toggleMobilePanel() {
            const panel = document.getElementById('mobilePanel');
            panel.classList.toggle('open');
        }

        function closeMobilePanel() {
            const panel = document.getElementById('mobilePanel');
            panel.classList.remove('open');
        }

        function toggleMobileSubmenu(element) {
            event.preventDefault();
            const submenu = element.nextElementSibling;
            const chevron = element.querySelector('.mobile-chevron');

            submenu.classList.toggle('open');
            chevron.classList.toggle('open');
        }

        // Close mobile panel when clicking outside
        document.addEventListener('click', function(event) {
            const panel = document.getElementById('mobilePanel');
            const toggle = document.querySelector('.mobile-toggle');

            if (!panel.contains(event.target) && !toggle.contains(event.target)) {
                panel.classList.remove('open');
            }
        });
    </script>
