        class Accordion {
            constructor(container) {
                this.container = container;
                this.sections = container.querySelectorAll('.accordion-section');
                this.init();
            }

            init() {
                // Set initial state - first section open
                const firstSection = this.sections[0];
                this.setInitialHeight(firstSection);

                // Add click listeners
                this.sections.forEach(section => {
                    const header = section.querySelector('.accordion-header');
                    header.addEventListener('click', () => this.handleClick(section));
                });
            }

            setInitialHeight(section) {
                const content = section.querySelector('.accordion-content');
                const inner = content.querySelector('.accordion-content-inner');

                // Temporarily make it visible to measure
                content.style.height = 'auto';
                content.style.visibility = 'visible';

                // Get the actual height including padding
                const height = inner.scrollHeight + 48; // 24px padding top + 24px padding bottom
                content.style.height = height + 'px';
            }

            handleClick(clickedSection) {
                const clickedHeader = clickedSection.querySelector('.accordion-header');
                const clickedContent = clickedSection.querySelector('.accordion-content');
                const clickedArrow = clickedSection.querySelector('.accordion-arrow');
                const isCurrentlyOpen = clickedHeader.classList.contains('active');

                // Close all sections first
                this.sections.forEach(section => {
                    const header = section.querySelector('.accordion-header');
                    const content = section.querySelector('.accordion-content');
                    const arrow = section.querySelector('.accordion-arrow');

                    if (header.classList.contains('active')) {
                        header.classList.remove('active');
                        arrow.classList.remove('rotated');
                        content.style.height = '0px';
                    }
                });

                // If the clicked section wasn't open, open it
                if (!isCurrentlyOpen) {
                    clickedHeader.classList.add('active');
                    clickedArrow.classList.add('rotated');

                    // Calculate and set the height with padding included
                    const inner = clickedContent.querySelector('.accordion-content-inner');

                    // Temporarily set height to auto to measure
                    clickedContent.style.height = 'auto';
                    const height = inner.scrollHeight + 48; // 24px padding top + 24px padding bottom

                    // Reset to 0 and then animate to the measured height
                    clickedContent.style.height = '0px';

                    // Force a reflow before animating
                    clickedContent.offsetHeight;

                    // Now animate to the target height
                    clickedContent.style.height = height + 'px';
                }
            }
        }

        // Initialize accordion when DOM is loaded
        document.addEventListener('DOMContentLoaded', () => {
            const accordionContainer = document.querySelector('.accordion-container');
            new Accordion(accordionContainer);
        });

        // Auto-demo functionality to show accordion working
