                this.startTime = null;
                this.animationId = null;
                this.confettiPieces = [];
                this.confettiAnimationId = null;

                this.colors = ['#ff6b6b', '#4ecdc4', '#45b7d1', '#f9ca24', '#f0932b', '#eb4d4b', '#6c5ce7', '#a29bfe', '#fd79a8', '#00b894'];

                this.init();
            }

            init() {
                this.restartButton.addEventListener('click', () => this.restart());
                this.start();
            }

