            animate() {
                const currentTime = performance.now();
                const elapsed = currentTime - this.startTime;
                const progress = Math.min(elapsed / this.duration, 1);

                // Update progress bar with linear timing
                const percentage = Math.floor(progress * 100);
                this.progressBar.style.width = (progress * 100) + '%';
                this.progressText.textContent = percentage + '%';

                // Change text color based on progress for better contrast
                if (progress > 0.5) {
                    this.progressText.classList.add('white');
                } else {
                    this.progressText.classList.remove('white');
                }

                if (progress < 1) {
                    this.animationId = requestAnimationFrame(() => this.animate());
                } else {
                    // Ensure exactly 100% at completion
                    this.progressBar.style.width = '100%';
                    this.progressText.textContent = '100%';
                    this.progressText.classList.add('white');
                    this.complete();
                }
            }

            complete() {
                // Show completion message with animation
                this.completionMessage.style.display = 'flex';

                // Create confetti burst
                this.createConfetti();

                // Show restart button after completion animation
                setTimeout(() => {
                    this.restartButton.style.display = 'block';
                }, 800);
            }

            createConfetti() {
                const progressRect = this.progressBar.getBoundingClientRect();
                const centerX = progressRect.left + progressRect.width / 2;
                const centerY = progressRect.top + progressRect.height / 2;

                // Create 90 confetti pieces to guarantee 80+ visible pieces
                for (let i = 0; i < 90; i++) {
                    this.createConfettiPiece(centerX, centerY);
                }

                // Start confetti animation
                this.animateConfetti();
