            createConfettiPiece(centerX, centerY) {
                const piece = document.createElement('div');
                piece.className = 'confetti-piece';

                // Random properties with guaranteed variation
                const size = Math.random() * 6 + 4; // 4-10px
                const color = this.colors[Math.floor(Math.random() * this.colors.length)];
                const velocityX = (Math.random() - 0.5) * 800; // Wide horizontal spread
                const velocityY = Math.random() * -500 - 300; // Strong initial upward velocity
                const rotationSpeed = (Math.random() - 0.5) * 720; // Rotation speed
                const gravity = Math.random() * 200 + 500; // Gravity

                piece.style.width = size + 'px';
                piece.style.height = size + 'px';
                piece.style.backgroundColor = color;
                piece.style.left = (centerX - size/2) + 'px';
                piece.style.top = (centerY - size/2) + 'px';
                piece.style.zIndex = '1001';

                // Store physics properties
