            animateConfetti() {
                const currentTime = performance.now();
                let allPiecesFaded = true;

                this.confettiPieces.forEach(piece => {
                    const elapsed = (currentTime - piece.startTime) / 1000; // Convert to seconds
                    const deltaTime = 1/60; // Fixed delta time for consistent physics

                    // Update velocity with gravity
                    piece.velocityY += piece.gravity * deltaTime;

                    // Update position
                    piece.x += piece.velocityX * deltaTime;
                    piece.y += piece.velocityY * deltaTime;

                    // Update rotation
                    piece.rotation += piece.rotationSpeed * deltaTime;

                    // Apply transformations
                    piece.style.left = piece.x + 'px';
                    piece.style.top = piece.y + 'px';
                    piece.style.transform = `rotate(${piece.rotation}deg)`;

                    // Fade out after 2.5 seconds
                    if (elapsed > 2.5) {
                        piece.opacity = Math.max(0, 1 - (elapsed - 2.5) * 2);
                        piece.style.opacity = piece.opacity;
                        if (piece.opacity > 0) {
                            allPiecesFaded = false;
                        }
                    } else {
                        allPiecesFaded = false;
                    }
                });

                // Continue animation if pieces are still visible and within time limit
                if (!allPiecesFaded && currentTime - this.confettiPieces[0]?.startTime < 4000) {
                    this.confettiAnimationId = requestAnimationFrame(() => this.animateConfetti());
                } else {
                    this.clearConfetti();
                }
            }

            clearConfetti() {
                if (this.confettiAnimationId) {
                    cancelAnimationFrame(this.confettiAnimationId);
                    this.confettiAnimationId = null;
                }

                this.confettiPieces.forEach(piece => {
                    if (piece.parentNode) {
                        piece.parentNode.removeChild(piece);
                    }
                });
                this.confettiPieces = [];
            }

            restart() {
                // Cancel any ongoing animations
                if (this.animationId) {
                    cancelAnimationFrame(this.animationId);
                    this.animationId = null;
                }

                // Clear confetti
                this.clearConfetti();

                // Reset UI elements
                this.progressBar.style.width = '0%';
                this.progressText.textContent = '0%';
                this.progressText.classList.remove('white');
                this.completionMessage.style.display = 'none';
                this.restartButton.style.display = 'none';

                // Start new animation with slight delay
                setTimeout(() => {
                    this.start();
                }, 100);
            }
        }

        // Initialize the animation when the page loads
        window.addEventListener('load', () => {
            new ProgressBarAnimation();
        });
    </script>
